          pointRadius: 0,
        },
        {
          label: 'RAM (MB)',
          data: chartState.ramData,
          yAxisID: 'y1',
          borderColor: palette.ram,
          backgroundColor: hexToRgba(palette.ram, 0.12),
          fill: true,
          tension: 0.35,
          borderWidth: 2,
          pointRadius: 0,
        },
      ],
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: {
          position: 'bottom',
          labels: {
            color: palette.ticks,
            usePointStyle: true,
            boxWidth: 10,
            boxHeight: 10,
            padding: 16,
          },
        },
        tooltip: {
          backgroundColor: palette.tooltipBg,
          borderColor: palette.tooltipBorder,
          borderWidth: 1,
          titleColor: getCssVar('--text-primary') || '#E5E7EB',
          bodyColor: getCssVar('--text-primary') || '#E5E7EB',
          padding: 10,
        },
      },
      scales: {
        x: {
          ticks: { color: palette.ticks, autoSkip: true, maxRotation: 0 },
          grid: { color: palette.grid },
        },
        y: {
          beginAtZero: true,
          suggestedMax: 100,
          ticks: { color: palette.ticks },
          grid: { color: palette.grid },
        },
        y1: {
          beginAtZero: true,
          position: 'right',
          ticks: { color: palette.ticks },
          grid: { drawOnChartArea: false },
        },
      },
