  transform: translateY(-2px);
}

.header-card {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-md);
  padding: var(--space-lg) var(--space-xl);
  margin-bottom: var(--space-lg);
}

.brand-block {
  display: flex;
